# Unit Tests for `hex_to_rgb`

```python
import pytest


def hex_to_rgb(h: str) -> tuple:
    h = h.lstrip('#')
    return tuple(int(h[i:i+2], 16) for i in (0, 2, 4))


class TestHexToRgbHappyPath:
    """Test typical, valid inputs."""

    def test_black(self):
        assert hex_to_rgb("#000000") == (0, 0, 0)

    def test_white(self):
        assert hex_to_rgb("#FFFFFF") == (255, 255, 255)

    def test_red(self):
        assert hex_to_rgb("#FF0000") == (255, 0, 0)

    def test_green(self):
        assert hex_to_rgb("#00FF00") == (0, 255, 0)

    def test_blue(self):
        assert hex_to_rgb("#0000FF") == (0, 0, 255)

    def test_arbitrary_color(self):
        assert hex_to_rgb("#1A2B3C") == (26, 43, 60)

    def test_returns_tuple(self):
        result = hex_to_rgb("#123456")
        assert isinstance(result, tuple)
        assert len(result) == 3

    @pytest.mark.parametrize("hex_input,expected", [
        ("#FF5733", (255, 87, 51)),
        ("#C70039", (199, 0, 57)),
        ("#900C3F", (144, 12, 63)),
        ("#581845", (88, 24, 69)),
        ("#DAF7A6", (218, 247, 166)),
    ])
    def test_various_colors(self, hex_input, expected):
        assert hex_to_rgb(hex_input) == expected


class TestHexToRgbEdgeCases:
    """Test edge cases and unusual but acceptable inputs."""

    def test_without_hash_prefix(self):
        """Function should handle hex without leading #."""
        assert hex_to_rgb("FF0000") == (255, 0, 0)

    def test_lowercase_hex(self):
        assert hex_to_rgb("#abcdef") == (171, 205, 239)

    def test_uppercase_hex(self):
        assert hex_to_rgb("#ABCDEF") == (171, 205, 239)

    def test_mixed_case_hex(self):
        assert hex_to_rgb("#aBcDeF") == (171, 205, 239)

    def test_multiple_hash_prefixes(self):
        """lstrip removes all leading #, this is current behavior."""
        assert hex_to_rgb("###FF0000") == (255, 0, 0)

    def test_max_value_per_channel(self):
        assert hex_to_rgb("#FFFFFF") == (255, 255, 255)

    def test_min_value_per_channel(self):
        assert hex_to_rgb("#000000") == (0, 0, 0)

    def test_all_values_in_valid_range(self):
        """Each channel value must be in [0, 255]."""
        result = hex_to_rgb("#A1B2C3")
        for channel in result:
            assert 0 <= channel <= 255


class TestHexToRgbErrorCases:
    """Test invalid inputs that should raise exceptions."""

    def test_empty_string_raises(self):
        with pytest.raises(ValueError):
            hex_to_rgb("")

    def test_only_hash_raises(self):
        with pytest.raises(ValueError):
            hex_to_rgb("#")

    def test_too_short_raises(self):
        with pytest.raises(ValueError):
            hex_to_rgb("#FFF")

    def test_too_short_no_hash_raises(self):
        with pytest.raises(ValueError):
            hex_to_rgb("FF00")

    def test_invalid_characters_raises(self):
        with pytest.raises(ValueError):
            hex_to_rgb("#GGHHII")

    def test_non_hex_special_characters_raises(self):
        with pytest.raises(ValueError):
            hex_to_rgb("#XX!@#$")

    def test_none_input_raises(self):
        with pytest.raises(AttributeError):
            hex_to_rgb(None)

    def test_integer_input_raises(self):
        with pytest.raises(AttributeError):
            hex_to_rgb(0xFF0000)

    def test_list_input_raises(self):
        with pytest.raises(AttributeError):
            hex_to_rgb(["#", "F", "F", "0", "0", "0", "0"])

    def test_whitespace_only_raises(self):
        with pytest.raises(ValueError):
            hex_to_rgb("      ")

    def test_internal_whitespace_raises(self):
        with pytest.raises(ValueError):
            hex_to_rgb("#FF 000")

    def test_seven_chars_no_hash_raises(self):
        """7 chars without '#' will pick wrong slices but still parse;
        ensure we test a clearly malformed 7-char string."""
        with pytest.raises(ValueError):
            hex_to_rgb("ZZZZZZZ")
```

### Notes on coverage

- **Happy path**: Standard 6-digit hex codes with `#`, primary colors, parametrized test over diverse colors, and a return-type check.
- **Edge cases**: No `#` prefix (works due to `lstrip`), case-insensitivity, multiple `#` prefixes, and channel boundary values.
- **Error cases**: Empty strings, too-short inputs, invalid hex characters, non-string types (`None`, `int`, `list`), and whitespace.

The tests document current behavior — note that `lstrip('#')` strips *all* leading `#` characters, and the function does **not** validate length or accept 3-digit shorthand like `#FFF`. If those are bugs you want to fix, the corresponding tests serve as a TODO checklist.
